export default function Seat({ seat, onClick }) {
	return (
		<button
			onClick={() => onClick(seat.seatNumber)}
			style={{
				margin: 5,
				padding: 10,
				background: seat.status === "OPEN" ? "green" : "red",
				color: "white",
			}}>
			{seat.seatNumber}
		</button>
	);
}
